def _read_json_file(path: Path) -> Any:
    try:
        if not path.exists():
            return None
        return json.loads(path.read_text(encoding="utf-8-sig"))
    except Exception:
        return None


def _atomic_write_text(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    fd, temp_name = tempfile.mkstemp(prefix=f".{path.name}.", suffix=".tmp", dir=str(path.parent))
    temp_path = Path(temp_name)
    try:
        with os.fdopen(fd, "w", encoding="utf-8", newline="\n") as handle:
            handle.write(content)
            handle.flush()
            os.fsync(handle.fileno())
        os.replace(temp_path, path)
        if os.name != "nt":
            directory_fd = os.open(str(path.parent), os.O_RDONLY)
            try:
                os.fsync(directory_fd)
            finally:
                os.close(directory_fd)
    except Exception:
        with contextlib.suppress(FileNotFoundError):
            temp_path.unlink()
        raise


def _atomic_write_bytes(path: Path, content: bytes) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    fd, temp_name = tempfile.mkstemp(prefix=f".{path.name}.", suffix=".tmp", dir=str(path.parent))
    temp_path = Path(temp_name)
    try:
        with os.fdopen(fd, "wb") as handle:
            handle.write(content)
            handle.flush()
            os.fsync(handle.fileno())
        os.replace(temp_path, path)
    except Exception:
        with contextlib.suppress(FileNotFoundError):
            temp_path.unlink()
        raise


def _write_json_file(path: Path, payload: Any) -> None:
    _atomic_write_text(path, json.dumps(payload, ensure_ascii=False, indent=2))


def _extract_persona_archive_list(raw: Any) -> list[dict[str, Any]]:
    if isinstance(raw, list):
        return [item for item in raw if isinstance(item, dict)]
    if isinstance(raw, dict):
        for key in ("persona_archives_v2", "persona_archives", "archives", "items"):
            value = raw.get(key)
            if isinstance(value, str):
                parsed = _json_loads(value, [])
                if isinstance(parsed, list):
                    return [item for item in parsed if isinstance(item, dict)]
            if isinstance(value, list):
                return [item for item in value if isinstance(item, dict)]
    return []


def _is_workflow_persona_archive(archive: Any) -> bool:
    if not isinstance(archive, dict):
        return False
    archive_id = str(archive.get("id") or "").strip().lower()
    if archive_id.startswith("workflow-persona-"):
        return True
    top_level_workflow = archive.get("imageWorkflow")
    if isinstance(top_level_workflow, dict) and top_level_workflow:
        return True
    setup = archive.get("setup") if isinstance(archive.get("setup"), dict) else {}
    setup_workflow = setup.get("imageWorkflow")
    if isinstance(setup_workflow, dict) and setup_workflow:
        return True
    return False


def _filter_active_persona_archives(archives: list[dict[str, Any]]) -> list[dict[str, Any]]:
    return [archive for archive in archives if isinstance(archive, dict) and not _is_workflow_persona_archive(archive)]


PERSONA_DASHBOARD_REFRESH_TASKS: dict[str, dict[str, Any]] = {}
PERSONA_DASHBOARD_REFRESH_LOCK = threading.Lock()
PERSONA_DASHBOARD_ARCHIVE_LOCK_TIMEOUT_SECONDS = 30
PERSONA_DASHBOARD_ARCHIVE_THREAD_LOCK = threading.RLock()
PERSONA_DASHBOARD_ARCHIVE_LOCK_STATE = threading.local()
PERSONA_DASHBOARD_MONITOR_LOCK = threading.Lock()
PERSONA_DASHBOARD_MONITOR_STARTED = False
PERSONA_DASHBOARD_MONITOR_STATE: dict[str, Any] = {
    "enabled": False,
    "source": "browser",
    "status": "idle",
    "last_task_id": "",
    "last_started_at": "",
    "last_finished_at": "",
    "last_message": "",
    "interval_seconds": 0,
}


def _remove_stale_lock_file(lock_path: Path, *, max_age_seconds: int = 300) -> bool:
    try:
        raw = lock_path.read_text(encoding="utf-8").strip().split()
        pid = int(raw[0]) if raw else 0
        created_at = float(raw[1]) if len(raw) > 1 else float(lock_path.stat().st_mtime)
    except Exception:
        pid = 0
        try:
            created_at = float(lock_path.stat().st_mtime)
        except Exception:
            return False
    stale = time.time() - created_at > max_age_seconds
    if not stale and os.name != "nt" and pid > 0:
        try:
            os.kill(pid, 0)
        except ProcessLookupError:
            stale = True
        except (PermissionError, OSError):
            pass
    if not stale:
        return False
    try:
        lock_path.unlink()
        return True
    except FileNotFoundError:
        return True
    except Exception:
        return False


@contextlib.contextmanager
def _persona_archive_file_lock(timeout_seconds: int = PERSONA_DASHBOARD_ARCHIVE_LOCK_TIMEOUT_SECONDS):
    with PERSONA_DASHBOARD_ARCHIVE_THREAD_LOCK:
        depth = int(getattr(PERSONA_DASHBOARD_ARCHIVE_LOCK_STATE, "depth", 0) or 0)
        if depth > 0:
            PERSONA_DASHBOARD_ARCHIVE_LOCK_STATE.depth = depth + 1
            try:
                yield
            finally:
                PERSONA_DASHBOARD_ARCHIVE_LOCK_STATE.depth = depth
            return

        lock_path = TOOL_R18_RUNTIME_DIR / "persona_archives.lock"
        lock_path.parent.mkdir(parents=True, exist_ok=True)
        started = time.time()
        fd: int | None = None
        while True:
            try:
                fd = os.open(str(lock_path), os.O_CREAT | os.O_EXCL | os.O_WRONLY)
                os.write(fd, f"{os.getpid()} {time.time()}\n".encode("utf-8"))
                break
            except FileExistsError:
                if _remove_stale_lock_file(lock_path):
                    continue
                if time.time() - started > timeout_seconds:
                    raise HTTPException(status_code=409, detail="人设归档正在写入，请稍后重试。")
                time.sleep(0.1)
        PERSONA_DASHBOARD_ARCHIVE_LOCK_STATE.depth = 1
        try:
            yield
        finally:
            PERSONA_DASHBOARD_ARCHIVE_LOCK_STATE.depth = 0
            if fd is not None:
                with contextlib.suppress(Exception):
                    os.close(fd)
            with contextlib.suppress(FileNotFoundError):
                lock_path.unlink()


@contextlib.contextmanager
def _persona_group_file_lock(timeout_seconds: int = PERSONA_DASHBOARD_ARCHIVE_LOCK_TIMEOUT_SECONDS):
    lock_path = TOOL_R18_RUNTIME_DIR / "persona_groups.lock"
    lock_path.parent.mkdir(parents=True, exist_ok=True)
    started = time.time()
    fd: int | None = None
    while True:
        try:
            fd = os.open(str(lock_path), os.O_CREAT | os.O_EXCL | os.O_WRONLY)
            os.write(fd, f"{os.getpid()} {time.time()}\n".encode("utf-8"))
            break
        except FileExistsError:
            if _remove_stale_lock_file(lock_path):
                continue
            if time.time() - started > timeout_seconds:
                raise HTTPException(status_code=409, detail="人设分组正在写入，请稍后重试。")
            time.sleep(0.1)
    try:
        yield
    finally:
        if fd is not None:
            with contextlib.suppress(Exception):
                os.close(fd)
        with contextlib.suppress(FileNotFoundError):
            lock_path.unlink()


def _persona_group_write_locked(operation):
    def locked(*args, **kwargs):
        with _persona_group_file_lock():
            return operation(*args, **kwargs)

    locked.__name__ = operation.__name__
    locked.__doc__ = operation.__doc__
    return locked


def _account_purge_workspace_paths() -> tuple[Path, ...]:
    return (
        TOOL_R18_RUNTIME_DIR / "persona_archives.json",
        TOOL_R18_RUNTIME_DIR / "persona_archives_cache.json",
        TOOL_R18_RUNTIME_DIR / "persona_groups.json",
        TOOL_R18_RUNTIME_DIR / "persona_memory.json",
        TOOL_R18_RUNTIME_DIR / "persona_dashboard_deleted_posts.json",
        TOOL_R18_RUNTIME_DIR / "persona_dashboard_hidden_memories.json",
        TOOL_R18_RUNTIME_DIR / "persona-list-summary-cache.json",
        TOOL_R18_RUNTIME_DIR / "persona-trend-intel-cache.json",
    )


def _account_purge_journal_dir(user_id: int) -> Path:
    return DATA_DIR / "account_purge_journal" / str(int(user_id))


def _create_account_purge_journal(user_id: int) -> Path:
    journal_dir = _account_purge_journal_dir(user_id)
    if journal_dir.exists():
        raise RuntimeError(f"purge journal already exists for user {int(user_id)}")
    journal_root = journal_dir.parent
    journal_root.mkdir(parents=True, exist_ok=True)
    temp_dir = journal_root / f".{int(user_id)}-{uuid.uuid4().hex}.tmp"
    temp_dir.mkdir(parents=False, exist_ok=False)
    try:
        entries: list[dict[str, Any]] = []
        with _persona_archive_file_lock():
            with _persona_group_file_lock():
                for index, path in enumerate(_account_purge_workspace_paths()):
                    if path.exists() and not path.is_file():
                        raise RuntimeError(f"purge workspace path is not a file: {path}")
                    existed = path.is_file()
                    snapshot_name = f"{index}.snapshot"
                    if existed:
                        (temp_dir / snapshot_name).write_bytes(path.read_bytes())
                    entries.append({"existed": existed, "snapshot": snapshot_name})
        _write_json_file(
            temp_dir / "manifest.json",
            {"version": 1, "target_user_id": int(user_id), "files": entries},
        )
        os.replace(temp_dir, journal_dir)
    except Exception:
        shutil.rmtree(temp_dir, ignore_errors=True)
        raise
    return journal_dir


def _stage_account_purge_paths(user_id: int, paths: list[Path]) -> None:
    journal_dir = _account_purge_journal_dir(user_id)
    manifest_path = journal_dir / "manifest.json"
    manifest = _read_json_file(manifest_path)
    if not isinstance(manifest, dict) or int(manifest.get("target_user_id") or 0) != int(user_id):
        raise RuntimeError(f"invalid purge journal for user {int(user_id)}")
    entries = manifest.get("staged_paths")
    if not isinstance(entries, list):
        entries = []
        manifest["staged_paths"] = entries
    seen = {str(item.get("original") or "") for item in entries if isinstance(item, dict)}
    stage_root = journal_dir / "staged"
    stage_root.mkdir(parents=True, exist_ok=True)
    for path in paths:
        original = path.expanduser().resolve()
        original_text = str(original)
        if original_text in seen or not original.exists():
            continue
        staged_rel = f"staged/{len(entries)}"
        entry = {
            "original": original_text,
            "staged": staged_rel,
            "kind": "directory" if original.is_dir() else "file",
            "status": "pending",
        }
        entries.append(entry)
        _write_json_file(manifest_path, manifest)
        staged_path = journal_dir / staged_rel
        staged_path.parent.mkdir(parents=True, exist_ok=True)
        shutil.move(str(original), str(staged_path))
        entry["status"] = "staged"
        _write_json_file(manifest_path, manifest)
        seen.add(original_text)


def _restore_account_purge_journal(user_id: int) -> None:
    journal_dir = _account_purge_journal_dir(user_id)
    manifest = _read_json_file(journal_dir / "manifest.json")
    paths = _account_purge_workspace_paths()
    entries = manifest.get("files") if isinstance(manifest, dict) else None
    if (
        not isinstance(entries, list)
        or int(manifest.get("version") or 0) != 1
        or int(manifest.get("target_user_id") or 0) != int(user_id)
        or len(entries) != len(paths)
    ):
        raise RuntimeError(f"invalid purge journal for user {int(user_id)}")

    restore_plan: list[tuple[Path, bytes | None]] = []
    for index, (path, entry) in enumerate(zip(paths, entries)):
        if not isinstance(entry, dict) or str(entry.get("snapshot") or "") != f"{index}.snapshot":
            raise RuntimeError(f"invalid purge journal entry {index} for user {int(user_id)}")
        if bool(entry.get("existed")):
            restore_plan.append((path, (journal_dir / f"{index}.snapshot").read_bytes()))
        else:
            restore_plan.append((path, None))

    staged_entries = manifest.get("staged_paths") or []
    if not isinstance(staged_entries, list):
        raise RuntimeError(f"invalid staged purge entries for user {int(user_id)}")
    for entry in reversed(staged_entries):
        if not isinstance(entry, dict):
            raise RuntimeError(f"invalid staged purge entry for user {int(user_id)}")
        original = Path(str(entry.get("original") or "")).expanduser().resolve()
        staged = (journal_dir / str(entry.get("staged") or "")).resolve()
        if journal_dir.resolve() not in staged.parents:
            raise RuntimeError(f"invalid staged purge path for user {int(user_id)}")
        if not staged.exists():
            continue
        if original.exists():
            raise RuntimeError(f"purge restore target already exists: {original}")
        original.parent.mkdir(parents=True, exist_ok=True)
        shutil.move(str(staged), str(original))

    with _persona_archive_file_lock():
        with _persona_group_file_lock():
            for path, content in restore_plan:
                if content is None:
                    path.unlink(missing_ok=True)
                else:
                    _atomic_write_bytes(path, content)


def _discard_account_purge_journal(user_id: int) -> None:
    journal_dir = _account_purge_journal_dir(user_id)
    if journal_dir.exists():
        shutil.rmtree(journal_dir)
    with contextlib.suppress(OSError):
        journal_dir.parent.rmdir()


def _persona_archive_write_locked(operation):
    def locked(*args, **kwargs):
        with _persona_archive_file_lock():
            return operation(*args, **kwargs)

    locked.__name__ = operation.__name__
    locked.__doc__ = operation.__doc__
    return locked


