def _normalize_hot_workflow_text(value: Any) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    for source, target in _HOT_WORKFLOW_SIMPLIFIED_REPLACEMENTS:
        text = text.replace(source, target)
    return re.sub(r"\s+", " ", text).strip()


_PERSONA_HOT_RUN_LOCK = threading.Lock()
_PERSONA_HOT_PROCESS_LOCK = threading.Lock()
_PERSONA_HOT_INTERACTIVE_REQUESTED = threading.Event()
_PERSONA_HOT_BACKGROUND_PROCESS: subprocess.Popen[str] | None = None
_PERSONA_HOT_LAST_INTERACTIVE_AT = 0.0


class _PersonaHotBackgroundDeferred(RuntimeError):
    pass


def _terminate_persona_hot_process(process: subprocess.Popen[str] | None) -> None:
    if process is None:
        return
    returncode = process.poll()
    if isinstance(returncode, int):
        return
    if os.name == "nt":
        process.terminate()
    else:
        with contextlib.suppress(ProcessLookupError):
            os.killpg(process.pid, signal.SIGTERM)
    try:
        process.wait(timeout=2)
    except subprocess.TimeoutExpired:
        if os.name == "nt":
            process.kill()
        else:
            with contextlib.suppress(ProcessLookupError):
                os.killpg(process.pid, signal.SIGKILL)
        with contextlib.suppress(subprocess.TimeoutExpired):
            process.wait(timeout=2)


def _run_persona_hot_workflow_cli(payload: dict[str, Any], timeout_seconds: int = 180, *, background: bool = False) -> dict[str, Any]:
    global _PERSONA_HOT_BACKGROUND_PROCESS, _PERSONA_HOT_LAST_INTERACTIVE_AT
    _sync_tool_r18_api_config_for_persona_workflow()
    command = [*_tool_r18_node_command("scripts/skills/persona-hot-workflow.ts"), json.dumps(payload, ensure_ascii=True)]
    timeout = min(max(30, int(timeout_seconds)), 120)
    process: subprocess.Popen[str] | None = None
    acquired = False
    if background:
        if _PERSONA_HOT_INTERACTIVE_REQUESTED.is_set() or not _PERSONA_HOT_RUN_LOCK.acquire(blocking=False):
            raise _PersonaHotBackgroundDeferred("页面热点任务优先，后台补池已延后。")
        acquired = True
        if _PERSONA_HOT_INTERACTIVE_REQUESTED.is_set():
            _PERSONA_HOT_RUN_LOCK.release()
            raise _PersonaHotBackgroundDeferred("页面热点任务优先，后台补池已延后。")
    else:
        _PERSONA_HOT_INTERACTIVE_REQUESTED.set()
        _PERSONA_HOT_LAST_INTERACTIVE_AT = time.time()
        with _PERSONA_HOT_PROCESS_LOCK:
            background_process = _PERSONA_HOT_BACKGROUND_PROCESS
        _terminate_persona_hot_process(background_process)
        _PERSONA_HOT_RUN_LOCK.acquire()
        acquired = True
        _PERSONA_HOT_INTERACTIVE_REQUESTED.clear()
    try:
        process = subprocess.Popen(
            command,
            cwd=str(ROOT_DIR / "tool_r18"),
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            encoding="utf-8",
            start_new_session=os.name != "nt",
            creationflags=subprocess.CREATE_NEW_PROCESS_GROUP if os.name == "nt" else 0,
        )
        if background:
            with _PERSONA_HOT_PROCESS_LOCK:
                _PERSONA_HOT_BACKGROUND_PROCESS = process
        stdout, stderr = process.communicate(timeout=timeout)
    except subprocess.TimeoutExpired as exc:
        _terminate_persona_hot_process(process)
        raise HTTPException(status_code=504, detail=f"热点抓取超过 {timeout} 秒，已终止本次任务。") from exc
    except FileNotFoundError as exc:
        raise HTTPException(status_code=500, detail="未找到 Node.js 或 tsx，无法执行热点抓取。") from exc
    finally:
        if background:
            with _PERSONA_HOT_PROCESS_LOCK:
                if _PERSONA_HOT_BACKGROUND_PROCESS is process:
                    _PERSONA_HOT_BACKGROUND_PROCESS = None
        if acquired:
            _PERSONA_HOT_RUN_LOCK.release()
    stdout = str(stdout or "").strip()
    stderr = str(stderr or "").strip()
    data = _parse_tool_r18_json_output(stdout)
    if process.returncode != 0:
        detail = str((data or {}).get("error") or stderr or stdout or "热点抓取失败。").strip()
        raise HTTPException(status_code=500, detail=detail)
    if not isinstance(data, dict):
        raise HTTPException(status_code=500, detail="热点抓取返回格式无效。")
    if data.get("ok") is False:
        raise HTTPException(status_code=500, detail=str(data.get("error") or "热点抓取失败。").strip())
    return data


def _warm_persona_hot_strategy_async(archive_id: str) -> None:
    clean_id = str(archive_id or "").strip()
    if not clean_id:
        return
    with _PERSONA_HOT_POOL_WORKER_LOCK:
        _PERSONA_HOT_WARM_PENDING.add(clean_id)
    _PERSONA_HOT_POOL_WAKE.set()


_PERSONA_HOT_POOL_WORKER_THREAD: threading.Thread | None = None
_PERSONA_HOT_POOL_WORKER_LOCK = threading.Lock()
_PERSONA_HOT_POOL_STOP = threading.Event()
_PERSONA_HOT_POOL_WAKE = threading.Event()
_PERSONA_HOT_POOL_ATTEMPTS: dict[str, float] = {}
_PERSONA_HOT_WARM_PENDING: set[str] = set()
_PERSONA_HOT_POOL_REFILLING: set[str] = set()
_PERSONA_HOT_POOL_COUNTS: dict[tuple[str, str], int] = {}
_PERSONA_HOT_POOL_STRATEGY_READY: dict[str, bool] = {}
_PERSONA_HOT_WARM_ATTEMPTS: dict[str, float] = {}
_PERSONA_HOT_POOL_CURSOR = 0


def _persona_hot_pool_worker_enabled() -> bool:
    return _to_bool(os.getenv("PERSONA_HOT_POOL_WORKER_ENABLED", "1"), True)


def _persona_hot_pool_resources_available() -> bool:
    try:
        if hasattr(os, "getloadavg") and os.getloadavg()[0] > max(1.0, float(os.cpu_count() or 1) * 0.8):
            return False
        meminfo = Path("/proc/meminfo")
        if meminfo.exists():
            match = re.search(r"^MemAvailable:\s+(\d+)\s+kB", meminfo.read_text(encoding="utf-8"), re.MULTILINE)
            if match and int(match.group(1)) < 768 * 1024:
                return False
    except Exception:
        return False
    return True


def _persona_hot_pool_worker_loop() -> None:
    global _PERSONA_HOT_POOL_CURSOR
    low_watermark = max(10, _to_int(os.getenv("PERSONA_HOT_POOL_LOW_WATERMARK"), 60))
    target_count = max(low_watermark, _to_int(os.getenv("PERSONA_HOT_POOL_TARGET_COUNT"), 100))
    stats_batch_size = max(1, min(10, _to_int(os.getenv("PERSONA_HOT_POOL_STATS_BATCH_SIZE"), 1)))
    interval_seconds = max(60, _to_int(os.getenv("PERSONA_HOT_POOL_INTERVAL_SECONDS"), 180))
    idle_seconds = max(30, _to_int(os.getenv("PERSONA_HOT_POOL_IDLE_SECONDS"), 120))
    cooldown_seconds = max(300, _to_int(os.getenv("PERSONA_HOT_POOL_COOLDOWN_SECONDS"), 900))
    warm_cooldown_seconds = max(900, _to_int(os.getenv("PERSONA_HOT_WARM_COOLDOWN_SECONDS"), 3600))
    while not _PERSONA_HOT_POOL_STOP.is_set():
        _PERSONA_HOT_POOL_WAKE.wait(interval_seconds)
        _PERSONA_HOT_POOL_WAKE.clear()
        if _PERSONA_HOT_POOL_STOP.is_set():
            break
        try:
            if not _persona_hot_pool_worker_enabled() or not _persona_hot_pool_resources_available():
                continue
            if time.time() - _PERSONA_HOT_LAST_INTERACTIVE_AT < idle_seconds:
                continue
            with _PERSONA_HOT_POOL_WORKER_LOCK:
                pending_warm_id = next(iter(_PERSONA_HOT_WARM_PENDING), "")
            if pending_warm_id:
                try:
                    _run_persona_hot_workflow_cli(
                        {"action": "warm-hot-strategy", "archiveId": pending_warm_id},
                        timeout_seconds=60,
                        background=True,
                    )
                except _PersonaHotBackgroundDeferred:
                    raise
                except Exception:
                    _PERSONA_HOT_WARM_ATTEMPTS[pending_warm_id] = time.time()
                    with _PERSONA_HOT_POOL_WORKER_LOCK:
                        _PERSONA_HOT_WARM_PENDING.discard(pending_warm_id)
                    raise
                else:
                    _PERSONA_HOT_WARM_ATTEMPTS[pending_warm_id] = time.time()
                    with _PERSONA_HOT_POOL_WORKER_LOCK:
                        _PERSONA_HOT_WARM_PENDING.discard(pending_warm_id)
                continue
            archives, _ = _read_tool_r18_persona_archives()
            archive_ids = [str(item.get("id") or "").strip() for item in archives if str(item.get("id") or "").strip()]
            if not archive_ids:
                continue
            batch_size = min(stats_batch_size, len(archive_ids))
            batch_ids = [archive_ids[(_PERSONA_HOT_POOL_CURSOR + offset) % len(archive_ids)] for offset in range(batch_size)]
            _PERSONA_HOT_POOL_CURSOR = (_PERSONA_HOT_POOL_CURSOR + batch_size) % len(archive_ids)
            stats_result = _run_persona_hot_workflow_cli(
                {"action": "pool-stats", "archiveIds": batch_ids},
                timeout_seconds=60,
                background=True,
            )
            pool_rows = [
                item for item in (stats_result.get("pools") if isinstance(stats_result.get("pools"), list) else [])
                if isinstance(item, dict)
            ]
            pool_counts = {
                (str(item.get("archiveId") or "").strip(), str(item.get("searchMode") or "strict").strip()): max(0, _to_int(item.get("readyCount"), 0))
                for item in pool_rows
            }
            _PERSONA_HOT_POOL_COUNTS.update(pool_counts)
            now = time.time()
            strategy_missing_ids = {
                str(item.get("archiveId") or "").strip()
                for item in pool_rows
                if item.get("strategyReady") is False and str(item.get("archiveId") or "").strip()
            }
            if strategy_missing_ids:
                with _PERSONA_HOT_POOL_WORKER_LOCK:
                    _PERSONA_HOT_WARM_PENDING.update(
                        archive_id for archive_id in strategy_missing_ids
                        if now - _PERSONA_HOT_WARM_ATTEMPTS.get(archive_id, 0.0) >= warm_cooldown_seconds
                    )
            for archive_id in batch_ids:
                _PERSONA_HOT_POOL_STRATEGY_READY[archive_id] = archive_id not in strategy_missing_ids
            candidates: list[tuple[int, int, float, str, str]] = []
            for archive_id in archive_ids:
                for search_mode in ("strict", "normal"):
                    key = f"{archive_id}:{search_mode}"
                    count_key = (archive_id, search_mode)
                    if count_key not in _PERSONA_HOT_POOL_COUNTS:
                        continue
                    ready_count = _PERSONA_HOT_POOL_COUNTS[count_key]
                    last_attempt = _PERSONA_HOT_POOL_ATTEMPTS.get(key, 0.0)
                    if ready_count >= target_count:
                        _PERSONA_HOT_POOL_REFILLING.discard(key)
                        continue
                    _PERSONA_HOT_POOL_REFILLING.add(key)
                    if now - last_attempt >= cooldown_seconds:
                        candidates.append((0 if ready_count < low_watermark else 1, ready_count, last_attempt, archive_id, search_mode))
            if not candidates:
                continue
            _, _, _, archive_id, search_mode = min(candidates)
            key = f"{archive_id}:{search_mode}"
            _PERSONA_HOT_POOL_ATTEMPTS[key] = now
            _run_persona_hot_workflow_cli({
                "action": "fetch-hot-candidates",
                "archiveId": archive_id,
                "limit": 10,
                "refresh": True,
                "searchMode": search_mode,
            }, timeout_seconds=120, background=True)
        except _PersonaHotBackgroundDeferred:
            continue
        except Exception as exc:
            print(f"[persona-hot-pool] background refill skipped: {exc}", flush=True)


def _start_persona_hot_pool_worker() -> None:
    global _PERSONA_HOT_POOL_WORKER_THREAD
    if not _persona_hot_pool_worker_enabled():
        return
    with _PERSONA_HOT_POOL_WORKER_LOCK:
        if _PERSONA_HOT_POOL_WORKER_THREAD is not None and _PERSONA_HOT_POOL_WORKER_THREAD.is_alive():
            return
        _PERSONA_HOT_POOL_STOP.clear()
        _PERSONA_HOT_POOL_WAKE.clear()
        thread = threading.Thread(target=_persona_hot_pool_worker_loop, name="persona-hot-pool-worker", daemon=True)
        _PERSONA_HOT_POOL_WORKER_THREAD = thread
        thread.start()


def _stop_persona_hot_pool_worker() -> None:
    _PERSONA_HOT_POOL_STOP.set()
    _PERSONA_HOT_POOL_WAKE.set()
    with _PERSONA_HOT_PROCESS_LOCK:
        process = _PERSONA_HOT_BACKGROUND_PROCESS
    _terminate_persona_hot_process(process)


def _persona_hot_raw_candidate_count(result: dict[str, Any]) -> int:
    candidates = result.get("candidates") if isinstance(result, dict) else []
    return len(candidates) if isinstance(candidates, list) else 0


def _persona_hot_user_warnings(raw_warnings: Any, candidate_count: int, limit: int, cookie_rows: Any = None) -> list[str]:
    count = max(0, int(candidate_count or 0))
    target = max(1, int(limit or 10))
    messages = [
        "暂未找到符合条件的热点，请稍后刷新候选。"
        if count <= 0
        else (f"已找到 {count} 条符合条件的热点，暂不足 {target} 条。" if count < target else f"已获取 {count} 条热点候选。")
    ]
    normalized = [
        _normalize_hot_workflow_text(item)
        for item in (raw_warnings if isinstance(raw_warnings, list) else [])
        if _normalize_hot_workflow_text(item)
    ]
    warning_text = " ".join(normalized).lower()
    threads_status = next((
        item for item in (cookie_rows if isinstance(cookie_rows, list) else [])
        if isinstance(item, dict) and str(item.get("platform") or "").strip().lower() == "threads"
    ), {})
    cookie_health = str(threads_status.get("health") or "").strip().lower()
    has_session = threads_status.get("has_required_session_cookie")
    valid_cookie_count = _to_int(threads_status.get("valid_cookie_count"), 0)
    expired_cookie_count = _to_int(threads_status.get("expired_cookie_count"), 0)
    model_unavailable = any(token in warning_text for token in (
        "模型当前不可用", "模型策略不可用", "模型热点搜索策略暂不可用", "模型生成热点搜索策略失败", "模型未返回可用",
    ))
    timed_out = "超时" in warning_text or "timeout" in warning_text or "timed out" in warning_text
    rate_limited = "限流" in warning_text or "rate limit" in warning_text or "too many requests" in warning_text
    if cookie_health == "missing":
        messages.append("Threads 账号尚未授权登录，请先到账号管理完成登录。")
    elif cookie_health == "expired" or (valid_cookie_count <= 0 and expired_cookie_count > 0):
        messages.append("Threads 登录 Cookie 已过期，请重新登录并同步 Cookie。")
    elif cookie_health == "degraded" and has_session is False:
        messages.append("Threads 账号未保持登录或缺少 sessionid，请重新登录并同步 Cookie。")
    elif cookie_health == "degraded":
        messages.append("Threads Cookie 部分失效，请刷新账号授权后重试。")
    elif rate_limited:
        messages.append("Threads 当前请求受限，请稍后重试。")
    elif model_unavailable:
        messages.append("模型暂不可用，请稍后重试。")
    elif timed_out:
        messages.append("本次抓取超时，结果可能不完整。")
    return messages[:2]


def _fetch_persona_hot_candidates(archive_id: str, payload: PersonaDashboardHotCandidatesFetchPayload) -> dict[str, Any]:
    clean_id = str(archive_id or "").strip()
    if not clean_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID。")

    memories = _list_selectable_persona_memories(clean_id)
    summary_by_id = {
        str(item.get("id") or "").strip(): str(item.get("summary") or "").strip()
        for item in memories
        if str(item.get("id") or "").strip() and str(item.get("summary") or "").strip()
    }
    selected_ids = [str(item or "").strip() for item in (payload.selected_memory_ids or []) if str(item or "").strip()]
    selected_summaries = (
        [summary_by_id[memory_id] for memory_id in selected_ids if memory_id in summary_by_id]
        if selected_ids
        else [str(item.get("summary") or "").strip() for item in memories if str(item.get("summary") or "").strip()]
    )[:8]
    limit = min(max(_to_int(payload.limit, 10), 1), 20)
    search_mode = "normal" if str(payload.search_mode or "").strip().lower() == "normal" else "strict"
    freshness_days = min(max(_to_int(payload.freshness_days, 7), 0), 15)
    result = _run_persona_hot_workflow_cli(
        {
            "action": "fetch-hot-candidates",
            "archiveId": clean_id,
            "prompt": str(payload.prompt or "").strip(),
            "refresh": bool(payload.refresh),
            "limit": limit,
            "searchMode": search_mode,
            "freshnessDays": freshness_days,
            "freshnessPolicy": "strict" if str(payload.freshness_policy or "").strip().lower() == "strict" else "legacy",
            "memorySummaries": selected_summaries,
        },
        timeout_seconds=120,
    )

    cookie_rows = []
    for item in result.get("cookieStatuses") if isinstance(result.get("cookieStatuses"), list) else []:
        if not isinstance(item, dict):
            continue
        cookie_rows.append({
            "platform": str(item.get("platform") or "").strip(),
            "label": _normalize_hot_workflow_text(item.get("label") or item.get("platform") or ""),
            "message": _normalize_hot_workflow_text(item.get("message") or item.get("health") or ""),
            "health": str(item.get("health") or "").strip(),
            "valid_cookie_count": _to_int(item.get("validCookieCount") or item.get("valid_cookie_count"), 0),
            "expired_cookie_count": _to_int(item.get("expiredCookieCount") or item.get("expired_cookie_count"), 0),
            "has_required_session_cookie": item.get("hasRequiredSessionCookie") if "hasRequiredSessionCookie" in item else item.get("has_required_session_cookie"),
            "recommended_action": str(item.get("recommendedAction") or item.get("recommended_action") or "").strip(),
        })

    candidates = [
        normalized
        for normalized in (
            _normalize_persona_hot_candidate(item)
            for item in (result.get("candidates") if isinstance(result.get("candidates"), list) else [])
        )
        if normalized
    ][:limit]
    return {
        "ok": True,
        "archive_name": str(result.get("archiveName") or result.get("archive_name") or "").strip(),
        "keywords": [
            _normalize_hot_workflow_text(item)
            for item in (result.get("keywords") if isinstance(result.get("keywords"), list) else [])
            if _normalize_hot_workflow_text(item)
        ],
        "search_mode": "normal" if str(result.get("searchMode") or search_mode).strip().lower() == "normal" else "strict",
        "freshness_days": min(max(_to_int(result.get("freshnessDays"), freshness_days), 0), 15),
        "freshness_policy": "strict" if str(result.get("freshnessPolicy") or payload.freshness_policy or "").strip().lower() == "strict" else "legacy",
        "cookie_statuses": cookie_rows,
        "warnings": _persona_hot_user_warnings(result.get("warnings"), len(candidates), limit, cookie_rows),
        "candidates": candidates,
    }


def _import_persona_hot_candidates(archive_id: str, payload: PersonaDashboardHotCandidatesImportPayload) -> dict[str, Any]:
    clean_id = str(archive_id or "").strip()
    if not clean_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID。")
    candidates = payload.candidates if isinstance(payload.candidates, list) else []
    cleaned_candidates = [item for item in candidates if isinstance(item, dict)]
    if not cleaned_candidates:
        raise HTTPException(status_code=400, detail="请先选择至少一条热点候选。")
    result = _run_persona_hot_workflow_cli(
        {
            "action": "import-hot-candidates",
            "archiveId": clean_id,
            "candidates": cleaned_candidates,
        },
        timeout_seconds=180,
    )
    posts = _list_persona_archive_posts(clean_id)
    post_by_id = {str(post.get("id") or "").strip(): post for post in posts if str(post.get("id") or "").strip()}
    imported_posts = []
    for item in result.get("posts") if isinstance(result.get("posts"), list) else []:
        if not isinstance(item, dict):
            continue
        post_id = str(item.get("id") or "").strip()
        if post_id and post_id in post_by_id:
            imported_posts.append(post_by_id[post_id])
    return {
        "ok": True,
        "archive_id": str(result.get("archiveId") or clean_id).strip(),
        "imported_count": _to_int(result.get("importedCount"), len(imported_posts)),
        "posts": imported_posts,
    }


def _refresh_persona_hot_post(archive_id: str, post_id: str) -> dict[str, Any]:
    clean_archive_id = str(archive_id or "").strip()
    clean_post_id = str(post_id or "").strip()
    if not clean_archive_id or not clean_post_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID 或草稿 ID。")
    result = _run_persona_hot_workflow_cli(
        {
            "action": "refresh-hot-post",
            "archiveId": clean_archive_id,
            "postId": clean_post_id,
        },
        timeout_seconds=180,
    )
    post = result.get("post") if isinstance(result.get("post"), dict) else None
    if not post:
        raise HTTPException(status_code=500, detail="热点数据已刷新，但未返回草稿数据。")
    return {"ok": True, "post": _compact_persona_archive_post(post)}


def _build_persona_generate_instruction(payload: PersonaDashboardGeneratePostsPayload) -> str:
    prompt = str(payload.prompt or "").strip()
    rewrite_source_post_id = str(getattr(payload, "rewrite_source_post_id", "") or "").strip()
    rewrite_source_title = str(getattr(payload, "rewrite_source_title", "") or "").strip()
    rewrite_source_content = str(getattr(payload, "rewrite_source_content", "") or "").strip()
    target_words = max(10, min(int(payload.target_words or 120), 2000))
    content_time_slot = str(payload.content_time_slot or "").strip().lower()
    lines: list[str] = []
    if rewrite_source_post_id or rewrite_source_content:
        lines.extend([
            "Task mode: rewrite the current draft post.",
            f"Rewrite source post id: {rewrite_source_post_id}",
            f"Rewrite source title: {rewrite_source_title}",
            f"Rewrite source content: {rewrite_source_content}",
            "Use the source content as reference only. Produce fresh rewritten draft posts for the same persona. Do not copy the source verbatim.",
        ])
    if prompt:
        lines.append(f"本次用户主题/要求（最高优先级）：{prompt}")
    else:
        lines.append("本次没有额外提示词，请根据当前人设自由生成新的推文主题。")
    lines.extend([
        "本次内容类型：常规推文内容。",
        "方向：适合日常发布、互动和平台安全，突出人设风格和内容表达。",
    ])
    if content_time_slot == "morning":
        lines.append("本次文案时段：早上文案。")
    elif content_time_slot == "night":
        lines.append("本次文案时段：晚上文案。")
    lines.extend([
        f"每篇目标字数：约 {target_words} 字。",
        "只生成推文文案草稿，不要输出说明、标题解释或思考过程。",
        "必须保持当前人设身份、语气和内容方向，避免重复旧内容。",
    ])
    return "\n".join(lines)


def _generate_persona_archive_posts(archive_id: str, payload: PersonaDashboardGeneratePostsPayload) -> dict[str, Any]:
    clean_id = str(archive_id or "").strip()
    if not clean_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID。")
    count = max(1, min(int(payload.count or 3), 20))
    content_time_slot = str(payload.content_time_slot or "").strip().lower()
    if content_time_slot not in {"", "morning", "night"}:
        raise HTTPException(status_code=400, detail="不支持的文案时段。")
    result = _run_persona_workflow_cli({
        "action": "generate-posts",
        "archiveId": clean_id,
        "count": count,
        "customInstruction": _build_persona_generate_instruction(payload),
        "selectedMemoryEntryIds": [str(item or "").strip() for item in (payload.selected_memory_ids or []) if str(item or "").strip()],
        "selectedMemorySummaries": [str(item or "").strip() for item in (payload.selected_memory_summaries or []) if str(item or "").strip()],
        "textModelBranch": "free",
    })
    post_ids = {
        str(item or "").strip()
        for item in (result.get("postIds") if isinstance(result.get("postIds"), list) else [])
        if str(item or "").strip()
    }
    posts = _list_persona_archive_posts(clean_id)
    generated_posts = [item for item in posts if str(item.get("id") or "").strip() in post_ids] if post_ids else posts[:count]
    return {
        "ok": True,
        "persona_id": clean_id,
        "generated_count": int(result.get("generatedCount") or len(generated_posts) or 0),
        "selected_memory_count": int(result.get("selectedMemoryCount") or 0),
        "post_ids": list(post_ids) if post_ids else [str(item.get("id") or "").strip() for item in generated_posts],
        "posts": generated_posts,
    }


def _find_persona_archive(archives: list[dict[str, Any]], archive_id: str) -> dict[str, Any] | None:
    clean_id = str(archive_id or "").strip()
    for archive in archives:
        if str(archive.get("id") or "").strip() == clean_id:
            return archive
    return None


def _persona_post_source_key(source: str = "posts") -> str:
    return "favoritePosts" if str(source or "").strip().lower() == "favorites" else "posts"


def _persona_post_source_name(source: str = "posts") -> str:
    return "favorites" if _persona_post_source_key(source) == "favoritePosts" else "posts"


def _is_published_persona_draft(post: dict[str, Any] | None) -> bool:
    if not isinstance(post, dict):
        return False
    return bool(str(post.get("publishedAt") or post.get("published_at") or "").strip())


def _list_persona_archive_posts(archive_id: str, source: str = "posts") -> list[dict[str, Any]]:
    clean_id = str(archive_id or "").strip()
    if not clean_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID。")
    _, _, archives = _persona_archive_source_for_write(clean_id)
    archive = _find_persona_archive(archives, clean_id)
    if not archive:
        raise HTTPException(status_code=404, detail="人设不存在。")
    source_key = _persona_post_source_key(source)
    posts = archive.get(source_key) if isinstance(archive.get(source_key), list) else []
    rows = []
    for post in posts:
        if not isinstance(post, dict):
            continue
        if source_key == "posts" and _is_published_persona_draft(post):
            continue
        compact = _compact_persona_archive_post(post)
        compact["source"] = _persona_post_source_name(source)
        compact["media_items"] = _previewable_persona_media_items(
            compact.get("media_items") if isinstance(compact.get("media_items"), list) else [],
            archive_id=clean_id,
            post_id=str(compact.get("id") or "").strip(),
            source=_persona_post_source_name(source),
        )
        rows.append(compact)
    rows.sort(key=lambda item: (str(item.get("published_at") or ""), str(item.get("updated_at") or ""), str(item.get("created_at") or "")), reverse=True)
    return rows


def _serve_persona_archive_post_media(archive_id: str, post_id: str, index: int, source: str = "posts") -> FileResponse:
    clean_archive_id = str(archive_id or "").strip()
    clean_post_id = str(post_id or "").strip()
    if not clean_archive_id or not clean_post_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID 或帖子 ID。")
    _, _, archives = _persona_archive_source_for_write(clean_archive_id)
    archive = _find_persona_archive(archives, clean_archive_id)
    if not archive:
        raise HTTPException(status_code=404, detail="人设不存在。")
    source_key = _persona_post_source_key(source)
    posts = archive.get(source_key) if isinstance(archive.get(source_key), list) else []
    raw_post = next(
        (item for item in posts if isinstance(item, dict) and str(item.get("id") or "").strip() == clean_post_id),
        None,
    )
    if not raw_post:
        raise HTTPException(status_code=404, detail="帖子不存在或已经删除。")
    published_meta = raw_post.get("publishedMeta") if isinstance(raw_post.get("publishedMeta"), dict) else {}
    media_items = _compact_dashboard_media_items(raw_post, published_meta)
    if index < 0 or index >= len(media_items):
        raise HTTPException(status_code=404, detail="媒体文件不存在。")
    raw_url = str((media_items[index] or {}).get("url") or "").strip()
    if not raw_url:
        raise HTTPException(status_code=404, detail="媒体文件不存在。")
    path = Path(raw_url).expanduser().resolve()
    if not path.is_file() or not _is_allowed_dashboard_media_path(path):
        raise HTTPException(status_code=404, detail="媒体源文件不存在。")
    return FileResponse(str(path), filename=path.name)


def _serve_persona_archive_publish_history_media(archive_id: str, history_id: str, index: int) -> FileResponse:
    clean_archive_id = str(archive_id or "").strip()
    clean_history_id = str(history_id or "").strip()
    if not clean_archive_id or not clean_history_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID 或发布记录 ID。")
    _, _, archives = _persona_archive_source_for_write(clean_archive_id)
    archive = _find_persona_archive(archives, clean_archive_id)
    if not archive:
        raise HTTPException(status_code=404, detail="人设不存在。")
    publish_history = archive.get("publishHistory") if isinstance(archive.get("publishHistory"), list) else []
    raw_record = next(
        (item for item in publish_history if isinstance(item, dict) and str(item.get("id") or "").strip() == clean_history_id),
        None,
    )
    if not raw_record:
        raise HTTPException(status_code=404, detail="发布记录不存在。")
    published_meta = raw_record.get("publishedMeta") if isinstance(raw_record.get("publishedMeta"), dict) else {}
    source_meta = raw_record.get("sourceMeta") if isinstance(raw_record.get("sourceMeta"), dict) else {}
    published_targets = raw_record.get("publishedTargets") if isinstance(raw_record.get("publishedTargets"), list) else []
    media_items = _compact_dashboard_media_items(raw_record, published_meta, source_meta, published_targets)
    if index < 0 or index >= len(media_items):
        raise HTTPException(status_code=404, detail="媒体文件不存在。")
    raw_url = str((media_items[index] or {}).get("url") or "").strip()
    if not raw_url:
        raise HTTPException(status_code=404, detail="媒体文件不存在。")
    path = Path(raw_url).expanduser().resolve()
    if not path.is_file() or not _is_allowed_dashboard_media_path(path):
        raise HTTPException(status_code=404, detail="媒体源文件不存在。")
    return FileResponse(str(path), filename=path.name)


def _list_persona_archive_publish_history(archive_id: str) -> list[dict[str, Any]]:
    clean_id = str(archive_id or "").strip()
    if not clean_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID。")
    _, _, archives = _persona_archive_source_for_write(clean_id)
    archive = _find_persona_archive(archives, clean_id)
    if not archive:
        raise HTTPException(status_code=404, detail="人设不存在。")
    publish_history = archive.get("publishHistory") if isinstance(archive.get("publishHistory"), list) else []
    rows = []
    for record in publish_history:
        if not _is_persona_publish_history_record(record):
            continue
        compact = _compact_publish_record(record, _publish_history_hot_metrics(record, archive))
        compact["media_items"] = _previewable_persona_media_items(
            compact.get("media_items") if isinstance(compact.get("media_items"), list) else [],
            archive_id=clean_id,
            history_id=str(compact.get("id") or "").strip(),
        )
        rows.append(compact)
    rows.sort(
        key=lambda item: (
            str(item.get("published_at") or ""),
            str(item.get("captured_at") or ""),
            str(item.get("id") or ""),
        ),
        reverse=True,
    )
    return rows


@_persona_archive_write_locked
def _requeue_persona_publish_record(archive_id: str, history_id: str) -> dict[str, Any]:
    clean_id = str(archive_id or "").strip()
    clean_history_id = str(history_id or "").strip()
    if not clean_id or not clean_history_id:
        raise HTTPException(status_code=400, detail="missing archive_id or history_id")
    path, raw, archives = _persona_archive_source_for_write(clean_id)
    archive = _find_persona_archive(archives, clean_id)
    if not archive:
        raise HTTPException(status_code=404, detail="persona not found")
    publish_history = archive.get("publishHistory") if isinstance(archive.get("publishHistory"), list) else []
    record = next((
        item for item in publish_history
        if isinstance(item, dict) and str(item.get("id") or item.get("archivePostId") or item.get("archive_post_id") or "").strip() == clean_history_id
    ), None)
    if not record or not _is_persona_publish_history_record(record):
        raise HTTPException(status_code=404, detail="publish history record not found")
    content = str(record.get("content") or record.get("caption") or "").strip()
    if not content:
        raise HTTPException(status_code=400, detail="publish history content is empty")
    posts = archive.get("posts") if isinstance(archive.get("posts"), list) else []
    next_order = max((int(_number(post.get("orderIndex"), -1)) for post in posts if isinstance(post, dict)), default=-1) + 1
    now = _persona_dashboard_iso_now()
    source_meta = copy.deepcopy(record.get("sourceMeta")) if isinstance(record.get("sourceMeta"), dict) else {}
    media_items = copy.deepcopy(record.get("mediaItems")) if isinstance(record.get("mediaItems"), list) else None
    if media_items is None and isinstance(record.get("media_items"), list):
        media_items = copy.deepcopy(record.get("media_items"))
    post = {
        "id": _new_persona_post_id(),
        "title": str(record.get("title") or f"重入队推文 #{len(posts) + 1}").strip(),
        "content": content,
        "wordCount": len(content),
        "orderIndex": next_order,
        "createdAt": now,
        "updatedAt": now,
        "sourceMeta": source_meta,
    }
    for key in ("imageUrl", "mediaUrl", "mediaType", "telegramGroupContentType"):
        value = record.get(key)
        if value:
            post[key] = value
    if media_items:
        post["mediaItems"] = media_items
    archive["posts"] = [*posts, post]
    archive["updatedAt"] = now
    _write_persona_archives_preserving_shape(path, raw, archives)
    compact = _compact_persona_archive_post(post)
    compact["media_items"] = _previewable_persona_media_items(
        compact.get("media_items") if isinstance(compact.get("media_items"), list) else [],
        archive_id=clean_id,
        post_id=str(compact.get("id") or "").strip(),
        source="posts",
    )
    return {
        "ok": True,
        "archive_id": clean_id,
        "history_id": clean_history_id,
        "post": compact,
        "posts": _list_persona_archive_posts(clean_id, "posts"),
    }


@_persona_archive_write_locked
def _create_persona_archive(payload: PersonaDashboardPersonaCreatePayload) -> dict[str, Any]:
    name = str(payload.name or "").strip()
