@_persona_archive_write_locked
def _duplicate_persona_archive(archive_id: str) -> dict[str, Any]:
    clean_id = str(archive_id or "").strip()
    if not clean_id:
        raise HTTPException(status_code=400, detail="missing archive_id")
    path, raw, archives = _persona_archive_source_for_write(clean_id)
    source = _find_persona_archive(archives, clean_id)
    if not source:
        raise HTTPException(status_code=404, detail="persona not found")
    now = _persona_dashboard_iso_now()
    source_name = str(source.get("name") or "").strip() or "\u672a\u547d\u540d\u4eba\u8bbe"
    duplicate_name = f"{source_name} \u526f\u672c"
    setup = copy.deepcopy(source.get("setup")) if isinstance(source.get("setup"), dict) else {}
    setup["personaName"] = duplicate_name
    setup["accountManagement"] = {"threads": {}}
    setup.pop("api_token", None)
    setup.pop("hotMetrics", None)
    duplicate = {
        "id": _new_persona_archive_id(),
        "name": duplicate_name,
        "content": str(source.get("content") or ""),
        "createdAt": now,
        "updatedAt": now,
        "setup": setup,
        "posts": [],
        "platformPosts": {"threads": [], "instagram": [], "telegram": []},
        "publishHistory": [],
        "personaImageLibrary": [],
    }
    archives.append(duplicate)
    _write_persona_archives_preserving_shape(path, raw, archives)
    _warm_persona_hot_strategy_async(str(duplicate.get("id") or ""))
    return {"ok": True, "profile": _build_persona_dashboard_profile(duplicate)}


def _persona_dashboard_suggest_keywords(payload: PersonaDashboardPersonaAiKeywordsPayload) -> dict[str, Any]:
    name = str(payload.name or "").strip()
    prompt = str(payload.prompt or "").strip()
    if not name:
        raise HTTPException(status_code=400, detail="persona name cannot be empty")
    if not prompt:
        raise HTTPException(status_code=400, detail="persona prompt cannot be empty")
    result = _run_persona_create_cli({
        "action": "suggest-keywords",
        "personaName": name,
        "userPrompt": prompt,
    }, timeout_seconds=90)
    keywords = [
        str(item or "").strip()
        for item in (result.get("keywords") if isinstance(result.get("keywords"), list) else [])
        if str(item or "").strip()
    ][:12]
    if len(keywords) != 5:
        raise HTTPException(status_code=502, detail="关键词提炼失败：模型未返回 5 个有效关键词，请稍后重试。")
    return {
        "ok": True,
        "name": name,
        "keywords": keywords,
    }


def _persona_dashboard_create_persona_with_ai(payload: PersonaDashboardPersonaAiCreatePayload) -> dict[str, Any]:
    name = str(payload.name or "").strip()
    prompt = str(payload.prompt or "").strip()
    selected_keywords = [
        str(item or "").strip()
        for item in (payload.selected_keywords or [])
        if str(item or "").strip()
    ][:2]
    if not name:
        raise HTTPException(status_code=400, detail="persona name cannot be empty")
    if not prompt:
        raise HTTPException(status_code=400, detail="persona prompt cannot be empty")
    result = _run_persona_create_cli({
        "action": "create-from-prompt",
        "personaName": name,
        "userPrompt": prompt,
        "selectedKeywords": selected_keywords,
    })
    archive_id = str(result.get("archiveId") or "").strip()
    if archive_id:
        _warm_persona_hot_strategy_async(archive_id)
        _, _, archives = _persona_archive_source_for_write(archive_id)
        archive = _find_persona_archive(archives, archive_id)
        if archive:
            return {
                "ok": True,
                "profile": _build_persona_dashboard_profile(archive),
                "selected_keywords": selected_keywords,
            }
    profile = {
        "id": archive_id,
        "name": str(result.get("name") or name).strip(),
        "content": str(result.get("content") or "").strip(),
        "setup": result.get("setup") if isinstance(result.get("setup"), dict) else {},
    }
    return {
        "ok": True,
        "profile": profile,
        "selected_keywords": selected_keywords,
    }


def _persona_dashboard_generate_profile_content(payload: PersonaDashboardPersonaAiProfilePayload) -> dict[str, Any]:
    name = str(payload.name or "").strip()
