@_persona_archive_write_locked
def _create_persona_archive_post(archive_id: str, payload: PersonaDashboardDraftPostPayload) -> dict[str, Any]:
    clean_id = str(archive_id or "").strip()
    if not clean_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID。")
    content = str(payload.content or "").strip()
    title = str(payload.title or "").strip()
    media_paths = [
        path for path in _extract_existing_file_paths(payload.media_paths)
        if _is_allowed_dashboard_media_path(Path(path))
    ]
    if not content and not media_paths:
        raise HTTPException(status_code=400, detail="推文正文和媒体不能同时为空。")
    path, raw, archives = _persona_archive_source_for_write(clean_id)
    archive = _find_persona_archive(archives, clean_id)
    if not archive:
        raise HTTPException(status_code=404, detail="人设不存在。")
    posts = archive.get("posts") if isinstance(archive.get("posts"), list) else []
    next_order = max((int(_number(post.get("orderIndex"), -1)) for post in posts if isinstance(post, dict)), default=-1) + 1
    now = _persona_dashboard_iso_now()
    record = {
        "id": _new_persona_post_id(),
        "title": title or (_persona_post_title(content, len(posts)) if content else f"媒体草稿 #{len(posts) + 1}"),
        "content": content,
        "wordCount": len(content),
        "orderIndex": next_order,
        "createdAt": now,
        "updatedAt": now,
    }
    if media_paths:
        media_items = _persona_post_media_items_from_paths(media_paths)
        first_media = media_items[0]
        record["mediaItems"] = media_items
        record["mediaUrl"] = first_media["url"]
        record["mediaType"] = first_media["type"]
    archive["posts"] = [*posts, record]
    archive["updatedAt"] = now
    _write_persona_archives_preserving_shape(path, raw, archives)
    return _compact_persona_archive_post(record)


def _favorite_source_post_id(post: dict[str, Any]) -> str:
    source_meta = post.get("sourceMeta") if isinstance(post.get("sourceMeta"), dict) else {}
    return str(source_meta.get("favoriteSourcePostId") or post.get("id") or "").strip()


@_persona_archive_write_locked
def _add_persona_favorite_post(archive_id: str, post_id: str) -> dict[str, Any]:
    clean_id = str(archive_id or "").strip()
    clean_post_id = str(post_id or "").strip()
    if not clean_id or not clean_post_id:
        raise HTTPException(status_code=400, detail="missing archive_id or post_id")
    path, raw, archives = _persona_archive_source_for_write(clean_id)
    archive = _find_persona_archive(archives, clean_id)
    if not archive:
        raise HTTPException(status_code=404, detail="人设不存在。")
    posts = archive.get("posts") if isinstance(archive.get("posts"), list) else []
    source_post = next((post for post in posts if isinstance(post, dict) and str(post.get("id") or "").strip() == clean_post_id), None)
    if not source_post or _is_published_persona_draft(source_post):
        raise HTTPException(status_code=404, detail="草稿已发布或已不存在。")
    favorites = archive.get("favoritePosts") if isinstance(archive.get("favoritePosts"), list) else []
    for favorite in favorites:
        if isinstance(favorite, dict) and _favorite_source_post_id(favorite) == clean_post_id:
            compact = _compact_persona_archive_post(favorite)
            compact["source"] = "favorites"
            return {"ok": True, "post": compact, "exists": True, "favorites": _list_persona_archive_posts(clean_id, "favorites")}
    now = _persona_dashboard_iso_now()
    record = copy.deepcopy(source_post)
    source_meta = record.get("sourceMeta") if isinstance(record.get("sourceMeta"), dict) else {}
    record.update({
        "id": _new_persona_post_id(),
        "title": str(record.get("title") or f"收藏推文 #{len(favorites) + 1}").strip(),
        "orderIndex": len(favorites),
        "createdAt": now,
        "updatedAt": now,
    })
    record.pop("publishedAt", None)
    record.pop("publishedMemory", None)
    record["sourceMeta"] = {
        **source_meta,
        "favoriteSourcePostId": clean_post_id,
        "favoriteAddedAt": now,
    }
    archive["favoritePosts"] = [*favorites, record]
    archive["updatedAt"] = now
    _write_persona_archives_preserving_shape(path, raw, archives)
    compact = _compact_persona_archive_post(record)
    compact["source"] = "favorites"
    compact["media_items"] = _previewable_persona_media_items(
        compact.get("media_items") if isinstance(compact.get("media_items"), list) else [],
        archive_id=clean_id,
        post_id=str(compact.get("id") or "").strip(),
        source="favorites",
    )
    return {"ok": True, "post": compact, "exists": False, "favorites": _list_persona_archive_posts(clean_id, "favorites")}


@_persona_archive_write_locked
def _delete_persona_favorite_post(archive_id: str, post_id: str) -> dict[str, Any]:
    clean_id = str(archive_id or "").strip()
    clean_post_id = str(post_id or "").strip()
    if not clean_id or not clean_post_id:
        raise HTTPException(status_code=400, detail="missing archive_id or post_id")
    path, raw, archives = _persona_archive_source_for_write(clean_id)
    archive = _find_persona_archive(archives, clean_id)
    if not archive:
        raise HTTPException(status_code=404, detail="persona not found")
    favorites = archive.get("favoritePosts") if isinstance(archive.get("favoritePosts"), list) else []
    next_favorites = [post for post in favorites if not (isinstance(post, dict) and str(post.get("id") or "").strip() == clean_post_id)]
    if len(next_favorites) == len(favorites):
        raise HTTPException(status_code=404, detail="favorite post not found")
    archive["favoritePosts"] = next_favorites
    archive["updatedAt"] = _persona_dashboard_iso_now()
    _write_persona_archives_preserving_shape(path, raw, archives)
    return {"ok": True, "archive_id": clean_id, "post_id": clean_post_id, "favorites": _list_persona_archive_posts(clean_id, "favorites")}


@_persona_archive_write_locked
def _update_persona_archive_post(archive_id: str, post_id: str, payload: PersonaDashboardDraftPostPayload, source: str = "posts") -> dict[str, Any]:
    clean_id = str(archive_id or "").strip()
    clean_post_id = str(post_id or "").strip()
    if not clean_id or not clean_post_id:
        raise HTTPException(status_code=400, detail="missing archive_id or post_id")
    content = str(payload.content or "").strip()
    title = str(payload.title or "").strip()
    path, raw, archives = _persona_archive_source_for_write(clean_id)
    archive = _find_persona_archive(archives, clean_id)
    if not archive:
        raise HTTPException(status_code=404, detail="persona not found")
    source_key = _persona_post_source_key(source)
    posts = archive.get(source_key) if isinstance(archive.get(source_key), list) else []
    target: dict[str, Any] | None = None
    target_index = 0
    for index, post in enumerate(posts):
        if isinstance(post, dict) and str(post.get("id") or "").strip() == clean_post_id:
            target = post
            target_index = index
            break
    if target is None:
        raise HTTPException(status_code=404, detail="post not found")
    current_media = [str(item.get("url") or "").strip() for item in _compact_dashboard_media_items(target) if str(item.get("url") or "").strip()]
    next_media = list(current_media)
    for raw_op in payload.media_ops or []:
        op = raw_op if isinstance(raw_op, dict) else {}
        op_type = str(op.get("type") or "").strip().lower()
        op_paths = [
            path for path in _extract_existing_file_paths(op.get("media_paths") or [])
            if _is_allowed_dashboard_media_path(Path(path))
        ]
        raw_index = int(_number(op.get("index"), -1))
        if op_type == "append" and op_paths:
            next_media.extend(path for path in op_paths if path not in next_media)
        elif op_type == "replace" and op_paths and 0 <= raw_index < len(next_media):
            next_media[raw_index:raw_index + 1] = op_paths
        elif op_type == "delete" and 0 <= raw_index < len(next_media):
            next_media.pop(raw_index)
    if not content and not next_media:
        raise HTTPException(status_code=400, detail="推文正文和媒体不能同时为空。")
    now = _persona_dashboard_iso_now()
    target["title"] = title or (_persona_post_title(content, target_index) if content else str(target.get("title") or "").strip() or f"媒体草稿 #{target_index + 1}")
    target["content"] = content
    target["wordCount"] = len(content)
    if payload.media_ops:
        media_items = _persona_post_media_items_from_paths(next_media)
        target["mediaItems"] = media_items
        if media_items:
            target["mediaUrl"] = media_items[0]["url"]
            target["mediaType"] = media_items[0]["type"]
        else:
            target.pop("mediaUrl", None)
            target.pop("mediaType", None)
    target["updatedAt"] = now
    archive["updatedAt"] = now
    _write_persona_archives_preserving_shape(path, raw, archives)
    compact = _compact_persona_archive_post(target)
    compact["source"] = _persona_post_source_name(source)
    return compact


def _persona_post_media_items_from_paths(paths: list[str]) -> list[dict[str, str]]:
    items: list[dict[str, str]] = []
    for raw_path in paths:
        text = str(raw_path or "").strip()
        if not text:
            continue
        items.append({
            "url": text,
            "type": _guess_media_type(text, "image"),
            "localPath": text,
        })
    return items


@_persona_archive_write_locked
def _update_persona_archive_post_media(archive_id: str, post_id: str, *, media_paths: list[str], replace_existing: bool = False, source: str = "posts", replace_index: int | None = None) -> dict[str, Any]:
    clean_archive_id = str(archive_id or "").strip()
    clean_post_id = str(post_id or "").strip()
    if not clean_archive_id or not clean_post_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID 或草稿 ID。")
    valid_paths = [
        path for path in _extract_existing_file_paths(media_paths)
        if _is_allowed_dashboard_media_path(Path(path))
    ]
    if not valid_paths:
        raise HTTPException(status_code=400, detail="没有可保存的媒体文件。")
    path, raw, archives = _persona_archive_source_for_write(clean_archive_id)
    archive = _find_persona_archive(archives, clean_archive_id)
    if not archive:
        raise HTTPException(status_code=404, detail="人设不存在。")
    source_key = _persona_post_source_key(source)
    posts = archive.get(source_key) if isinstance(archive.get(source_key), list) else []
    target: dict[str, Any] | None = None
    for post in posts:
        if isinstance(post, dict) and str(post.get("id") or "").strip() == clean_post_id:
            target = post
            break
    if target is None:
        raise HTTPException(status_code=404, detail="草稿不存在。")
    existing_items = _compact_dashboard_media_items(target)
    existing_paths = [str(item.get("url") or "").strip() for item in existing_items if str(item.get("url") or "").strip()]
    if replace_index is not None:
        if replace_index < 0 or replace_index >= len(existing_paths):
            raise HTTPException(status_code=404, detail="media item not found")
        merged_paths = [
            *existing_paths[:replace_index],
            *valid_paths,
            *existing_paths[replace_index + 1:],
        ]
    else:
        merged_paths = valid_paths if replace_existing else [
            *existing_paths,
            *valid_paths,
        ]
    merged_paths = _extract_existing_file_paths(merged_paths)
    media_items = _persona_post_media_items_from_paths(merged_paths)
    first = media_items[0] if media_items else {}
    target["mediaItems"] = media_items
    target["mediaUrl"] = str(first.get("url") or "")
    target["mediaType"] = str(first.get("type") or "")
    if str(first.get("type") or "") == "image":
        target["imageUrl"] = str(first.get("url") or "")
    else:
        target.pop("imageUrl", None)
    target["updatedAt"] = _persona_dashboard_iso_now()
    archive["updatedAt"] = target["updatedAt"]
    _write_persona_archives_preserving_shape(path, raw, archives)
    compact = _compact_persona_archive_post(target)
    compact["source"] = _persona_post_source_name(source)
    compact["media_items"] = _previewable_persona_media_items(
        compact.get("media_items") if isinstance(compact.get("media_items"), list) else [],
        archive_id=clean_archive_id,
        post_id=clean_post_id,
        source=_persona_post_source_name(source),
    )
    return {"ok": True, "post": compact}


@_persona_archive_write_locked
def _delete_persona_archive_post_media_item(archive_id: str, post_id: str, index: int, source: str = "posts") -> dict[str, Any]:
    clean_archive_id = str(archive_id or "").strip()
    clean_post_id = str(post_id or "").strip()
    if not clean_archive_id or not clean_post_id:
        raise HTTPException(status_code=400, detail="缺少人设 ID 或草稿 ID。")
    path, raw, archives = _persona_archive_source_for_write(clean_archive_id)
