    @app.post("/api/auth/logout")
    def api_logout(request: Request):
        admin_logout = request_uses_admin_session(request)
        admin_token = str(request.cookies.get(ADMIN_SESSION_COOKIE) or "").strip()
        user_token = str(request.cookies.get(SESSION_COOKIE) or "").strip()
        token = admin_token if admin_logout else user_token
        if token:
            with db() as conn:
                delete_session(conn, token)
        response = JSONResponse(content={"ok": True})
        response.delete_cookie(ADMIN_SESSION_COOKIE if admin_logout else SESSION_COOKIE)
        return response

    @app.post("/api/auth/change_password")
    def api_change_password(
        payload: ChangePasswordPayload,
        request: Request,
        user: dict[str, Any] = Depends(_get_user_allowing_password_change),
    ):
        if _is_admin_workspace(user):
            raise HTTPException(status_code=403, detail="请从管理员账号详情中修改客户密码")
        current_token = session_token_for_request(
            request,
            request.cookies.get(SESSION_COOKIE),
            request.cookies.get(ADMIN_SESSION_COOKIE),
        )
        old_pwd = str(payload.old_password or "")
        new_pwd = str(payload.new_password or "")
        if not verify_password(old_pwd, str(user.get("password_hash") or "")):
            raise HTTPException(status_code=400, detail="原密码错误")
        if int(user.get("must_change_password") or 0) == 1 and _password_expiry(user) <= _now_ts():
            if current_token:
                with db() as conn:
                    delete_session(conn, current_token)
            raise HTTPException(status_code=403, detail=_password_change_required_detail(user))
        minimum_length = _minimum_password_length(user)
        if not new_pwd or len(new_pwd) < minimum_length:
            raise HTTPException(status_code=400, detail=f"new password must be at least {minimum_length} characters")
        new_hash = hash_password(new_pwd)
        vault_ciphertext = None
        if not _is_admin(user):
            vault_ciphertext = _encrypt_password_for_vault(int(user["id"]), new_pwd)
        now = _now_ts()
        with db() as conn:
            conn.execute(
                "UPDATE users SET password_hash = ?, must_change_password = 0, "
                "password_expires_at = 0, updated_at = ? WHERE id = ?",
                (new_hash, now, int(user["id"])),
            )
            if vault_ciphertext is not None:
                _upsert_password_vault(
                    conn,
                    int(user["id"]),
                    vault_ciphertext,
                    now,
                    actor_user_id=int(user["id"]),
                    source="self_change",
                )
            if current_token:
                conn.execute(
                    "UPDATE sessions SET revoked_at = ?, revoke_reason = 'password_changed_other_session' "
                    "WHERE user_id = ? AND token <> ? AND revoked_at = 0",
                    (now, int(user["id"]), session_storage_token(current_token)),
                )
            else:
                conn.execute("DELETE FROM sessions WHERE user_id = ?", (int(user["id"]),))
        return {"ok": True}

    @app.post("/api/auth/change_username")
    def api_change_username(payload: ChangeUsernamePayload, user: dict[str, Any] = Depends(get_current_user)):
        if _is_admin_workspace(user):
            raise HTTPException(status_code=403, detail="管理员工作区不能使用客户自助账号设置")
        pwd = str(payload.password or "")
        new_username = str(payload.new_username or "").strip()
        current_username = str(user.get("username") or "").strip()
        if not verify_password(pwd, str(user.get("password_hash") or "")):
            raise HTTPException(status_code=400, detail="密码错误")
        if not new_username:
            raise HTTPException(status_code=400, detail="新用户名不能为空")
        if len(new_username) < 3 or len(new_username) > 32:
            raise HTTPException(status_code=400, detail="新用户名长度需在 3-32 之间")
        if not re.fullmatch(r"[a-zA-Z0-9._-]+", new_username):
            raise HTTPException(status_code=400, detail="新用户名仅支持字母/数字/.-_")
        if new_username == current_username:
            return {"ok": True}
        with db() as conn:
            row = conn.execute(
                "SELECT user_id FROM username_reservations WHERE username = ? COLLATE NOCASE",
                (new_username,),
            ).fetchone()
            if row is not None and int(row["user_id"] or 0) != int(user["id"]):
                raise HTTPException(status_code=400, detail="用户名已存在")
            _reserve_username(conn, int(user["id"]), new_username)
            conn.execute(
                "UPDATE users SET username = ?, updated_at = ? WHERE id = ?",
                (new_username, _now_ts(), int(user["id"])),
            )
        return {"ok": True}

    def _clean_user_avatar_url(value: str) -> str:
        clean = str(value or "").strip()
        if not clean:
            return ""
        if len(clean) > 900000:
            raise HTTPException(status_code=400, detail="avatar image is too large")
        lower = clean.lower()
        if lower.startswith("data:image/"):
            if ";base64," not in lower[:64]:
                raise HTTPException(status_code=400, detail="avatar data url must be base64 image")
            return clean
        if lower.startswith(("https://", "http://", "/assets/", "/uploads/")):
            return clean[:900000]
        raise HTTPException(status_code=400, detail="avatar must be an image url")

    def _clean_profile_tags(value: str) -> str:
        raw_items = re.split(r"[,，\n]+", str(value or ""))
        tags: list[str] = []
        seen: set[str] = set()
        for item in raw_items:
            tag = re.sub(r"\s+", " ", str(item or "").strip())
            if not tag:
                continue
            tag = tag[:18]
            key = tag.casefold()
            if key in seen:
                continue
            seen.add(key)
            tags.append(tag)
            if len(tags) >= 8:
                break
        return ", ".join(tags)

    def _user_profile_payload(row: dict[str, Any]) -> dict[str, Any]:
        return {
            "full_name": str(row.get("full_name") or ""),
            "avatar_url": str(row.get("avatar_url") or ""),
            "email": str(row.get("email") or ""),
            "phone": str(row.get("phone") or ""),
            "profile_signature": str(row.get("profile_signature") or ""),
            "profile_tags": str(row.get("profile_tags") or ""),
        }

    @app.patch("/api/me/profile")
    def api_update_me_profile(payload: UserProfilePayload, user: dict[str, Any] = Depends(get_current_user)):
        if _is_admin_workspace(user):
            raise HTTPException(status_code=403, detail="管理员工作区不能修改客户个人资料")
        full_name = str(payload.full_name or "").strip()
        if full_name and (len(full_name) < 2 or len(full_name) > 80):
            raise HTTPException(status_code=400, detail="显示名称长度需在 2-80 个字符之间")
        avatar_url = _clean_user_avatar_url(payload.avatar_url)
        email = str(payload.email or "").strip().lower()
        phone = str(payload.phone or "").strip()
        profile_signature = str(payload.profile_signature or "").strip()
        profile_tags = _clean_profile_tags(payload.profile_tags)
        if email and (len(email) > 160 or not re.fullmatch(r"[^\s@]+@[^\s@]+\.[^\s@]+", email)):
            raise HTTPException(status_code=400, detail="email format is invalid")
        if phone and (len(phone) < 6 or len(phone) > 32):
            raise HTTPException(status_code=400, detail="phone format is invalid")
        now = _now_ts()
        with db() as conn:
            conn.execute(
                "UPDATE users SET full_name = ?, avatar_url = ?, email = ?, phone = ?, profile_signature = ?, profile_tags = ?, updated_at = ? WHERE id = ?",
                (full_name, avatar_url, email, phone, profile_signature, profile_tags, now, int(user["id"])),
            )
            row = conn.execute("SELECT * FROM users WHERE id = ?", (int(user["id"]),)).fetchone()
        if row is None:
            raise HTTPException(status_code=404, detail="user not found")
        profile = _user_profile_payload(dict(row))
        return {"ok": True, "profile": profile, **profile}

