        return _update_persona_archive_post_media(
            archive_id,
            post_id,
            media_paths=saved_paths,
            replace_existing=_to_bool(replace_existing, False),
            replace_index=int(replace_index) if str(replace_index or "").strip().lstrip("-").isdigit() else None,
        )

